INSERT INTO `blog_author` VALUES (1, '三碗小鱼干', 'https://cos.pzhdv.cn/uploads/3dc8695d-c2a7-4c4f-896b-1495c3dec0aa.webp', '全栈开发者 & 技术博主', '5年+开发经验，专注React生态与云原生技术，热爱分享开发经验和前沿技术实践。', '1939673715@qq.com', 'https://pzhdv.cn', 'https://github.com/pzhdv', '18785384970', '码海探索者', '1996-12-20', '本科', '贵州师范大学');
INSERT INTO `blog_mission` VALUES (1, '📖 博客使命', '本博客致力于打造一个开放的技术交流平台', '分享现代Web开发实战经验&解析前沿技术架构方案&探讨研发效能提升之道&记录技术成长心路历程');
INSERT INTO `job_experience` VALUES (2, '开源贡献者', 'React社区', '2022-2023', 'iconfont icon-github', '维护2个千星开源项目&提交PR被合并50+次&组织本地技术Meetup');
