                                              `article_id` bigint(0) UNSIGNED NOT NULL COMMENT '文章ID',
                                              `category_id` bigint(0) UNSIGNED NOT NULL COMMENT '分类ID',
                                              PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 466 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '文章-分类关联表' ROW_FORMAT = Dynamic;

