                                 `mission_title` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '使命标题',
                                 `mission_description` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '使命描述',
                                 `mission_point_list_str` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL COMMENT '具体使命要点',
                                 PRIMARY KEY (`mission_id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 2 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '博客使命表' ROW_FORMAT = Dynamic;

